\begin{equation}
\mathcal{O}\!\Big(N^2 m\big(\eta+q_{\max}s_{\max}\big)\Big),
\end{equation}
where $q_{\max}:=\max_{k,r} q_r^{(k)}$ and
$s_{\max}:=\max_{k,r} s_r^{(k)}$.
\end{theorem}

